async function main() {
  console.log("📝 Seeding JHS remaining subjects (English, Social Studies, ICT, RME)...");
  await warmUp();
  let total = 0;
  total += await seedSubject("English Language", "JHS", jhsEnglishQuestions);
  total += await seedSubject("Social Studies", "JHS", jhsSocialStudiesQuestions);
  total += await seedSubject("ICT", "JHS", jhsICTQuestions);
  total += await seedSubject("RME", "JHS", jhsRMEQuestions);
  console.log(`✅ Total: ${total} questions seeded`);
}

main().catch(console.error).finally(() => prisma.$disconnect());
